  1→//! GraphQL HTTP handlers for the gateway.
  2→//!
  3→//! These handlers bridge `AppState` to the `moltis-graphql` schema, providing
  4→//! GraphiQL on GET `/graphql`, query/mutation execution on POST `/graphql`,
  5→//! and WebSocket subscriptions on GET `/graphql`.
  6→
  7→use std::sync::Arc;
  8→
  9→use {
 10→    async_graphql::http::{GraphiQLPlugin, GraphiQLSource},
 11→    async_trait::async_trait,
 12→    axum::{
 13→        Json,
 14→        extract::{FromRequestParts, Request, State, WebSocketUpgrade},
 15→        http::{HeaderMap, StatusCode, header},
 16→        response::{Html, IntoResponse, Response},
 17→    },
 18→    serde_json::Value,
 19→};
 20→
 21→use moltis_gateway::{
 22→    services::{ChatService, ServiceResult},
 23→    state::GatewayState,
 24→};
 25→
 26→use crate::server::AppState;
