120→pub fn build_graphql_schema(state: Arc<GatewayState>) -> moltis_graphql::MoltisSchema {
121→    let system_info = Arc::new(GatewaySystemInfoService {
122→        state: Arc::clone(&state),
123→    });
124→    let chat = Arc::new(GraphqlChatServiceProxy {
125→        state: Arc::clone(&state),
126→    });
127→    let services = state.services.to_services_with_chat(system_info, chat);
128→    moltis_graphql::build_schema(services, state.broadcaster.graphql_broadcast.clone())
129→}
