257→/// Handle GET `/graphql`:
258→///
259→/// - Standard HTTP GET: returns GraphiQL.
260→/// - WebSocket upgrade GET: upgrades to GraphQL subscriptions.
261→pub async fn graphql_get_handler(State(state): State<AppState>, req: Request) -> impl IntoResponse {
262→    if !state.gateway.is_graphql_enabled() {
263→        return graphql_disabled_response();
264→    }
265→
266→    let (mut parts, _body) = req.into_parts();
267→
268→    if is_websocket_upgrade_request(&parts.headers) {
269→        let protocol =
270→            match async_graphql_axum::GraphQLProtocol::from_request_parts(&mut parts, &()).await {
271→                Ok(protocol) => protocol,
272→                Err(status) => return status.into_response(),
273→            };
274→
275→        let ws = match WebSocketUpgrade::from_request_parts(&mut parts, &()).await {
276→            Ok(ws) => ws,
277→            Err(rejection) => return rejection.into_response(),
278→        };
279→
280→        return graphql_ws_response(&state, protocol, ws);
281→    }
282→
283→    graphiql_response()
284→}
285→
286→/// Handle GraphQL queries and mutations.
287→pub async fn graphql_handler(
288→    State(state): State<AppState>,
289→    req: async_graphql_axum::GraphQLRequest,
290→) -> impl IntoResponse {
291→    if !state.gateway.is_graphql_enabled() {
292→        return graphql_disabled_response();
293→    }
294→
295→    async_graphql_axum::GraphQLResponse::from(state.graphql_schema.execute(req.into_inner()).await)
296→        .into_response()
297→}
298→
299→fn graphql_ws_response(
300→    state: &AppState,
301→    protocol: async_graphql_axum::GraphQLProtocol,
302→    ws: WebSocketUpgrade,
303→) -> Response {
304→    let schema = state.graphql_schema.clone();
305→    ws.protocols(["graphql-transport-ws", "graphql-ws"])
306→        .on_upgrade(move |socket| {
307→            let resp = async_graphql_axum::GraphQLWebSocket::new(socket, schema, protocol);
308→            async move {
309→                resp.serve().await;
310→            }
311→        })
312→        .into_response()
313→}
314→
315→fn graphiql_response() -> Response {
316→    let asset_guard_plugin = GraphiQLPlugin {
317→        name: "MoltisGraphiQLAssetGuard",
318→        constructor: "",
319→        head_assets: Some(
320→            r##"<script>
321→  (function () {
322→    function fallbackUi() {
323→      if (window.React && window.React.createElement) {
324→        return window.React.createElement(
325→          "div",
326→          {
327→            style: {
328→              padding: "1rem",
329→              fontFamily: "system-ui, sans-serif",
330→              color: "#666"
331→            }
332→          },
333→          "GraphiQL assets failed to load. Check network access and reload."
334→        );
335→      }
336→      return null;
337→    }
338→
339→    if (!window.React) {
340→      window.React = {
341→        createElement: function () {
342→          return null;
343→        }
344→      };
345→    }
346→
347→    if (!window.GraphiQL) {
348→      function GraphiQLFallback() {
349→        return fallbackUi();
350→      }
351→      GraphiQLFallback.createFetcher = function () {
352→        return function () {
353→          return Promise.resolve();
354→        };
355→      };
356→      window.GraphiQL = GraphiQLFallback;
357→    }
358→
359→    if (!window.ReactDOM) {
360→      window.ReactDOM = {
361→        createRoot: function () {
362→          return {
363→            render: function () {
364→              var root = document.getElementById("graphiql");
365→              if (root) {
366→                root.textContent = "GraphiQL assets failed to load. Check network access and reload.";
367→                root.style.padding = "1rem";
368→                root.style.fontFamily = "system-ui, sans-serif";
369→                root.style.color = "#666";
370→              }
371→            }
372→          };
373→        }
374→      };
375→    }
376→  })();
377→</script>"##,
378→        ),
379→        body_assets: None,
380→        pre_configs: None,
381→        props: None,
382→    };
383→    let plugins = [asset_guard_plugin];
384→
385→    Html(
386→        GraphiQLSource::build()
387→            .endpoint("/graphql")
388→            .subscription_endpoint("/graphql")
389→            .plugins(&plugins)
390→            .finish(),
391→    )
392→    .into_response()
393→}
394→
395→fn graphql_disabled_response() -> Response {
396→    (
397→        StatusCode::SERVICE_UNAVAILABLE,
398→        Json(serde_json::json!({ "error": "graphql server is disabled" })),
399→    )
400→        .into_response()
401→}
402→
403→fn is_websocket_upgrade_request(headers: &HeaderMap) -> bool {
404→    // A proper WS upgrade has Connection: Upgrade AND Upgrade: websocket,
405→    // but we also accept the presence of Sec-WebSocket-Key as a fallback
406→    // since some clients (e.g. graphql-ws) may omit the Connection header.
407→    let has_upgrade_header = headers
408→        .get(header::UPGRADE)
409→        .and_then(|v| v.to_str().ok())
410→        .map(|v| {
411→            v.split(',')
412→                .any(|t| t.trim().eq_ignore_ascii_case("websocket"))
413→        })
414→        .unwrap_or(false);
415→
416→    has_upgrade_header || headers.contains_key(header::SEC_WEBSOCKET_KEY)
417→}
