  1→//! GraphQL subscription resolvers.
  2→//!
  3→//! Subscriptions bridge from the gateway's broadcast channel. Each subscription
  4→//! filters events by name and deserializes the payload into typed events.
  5→
  6→use std::sync::Arc;
  7→
  8→use {
  9→    async_graphql::{Context, Result, Subscription},
 10→    tokio_stream::Stream,
 11→};
 12→
 13→use crate::{
 14→    context::GqlContext,
 15→    types::{GenericEvent, TickEvent},
 16→};
 17→
 18→/// Root subscription type.
 19→#[derive(Default)]
 20→pub struct SubscriptionRoot;
 21→
 22→#[Subscription]
 23→impl SubscriptionRoot {
 24→    /// Chat events (streaming tokens, completion, abort).
 25→    async fn chat_event(
 26→        &self,
 27→        ctx: &Context<'_>,
 28→        session_key: Option<String>,
 29→    ) -> Result<impl Stream<Item = GenericEvent>> {
 30→        let c = ctx.data::<Arc<GqlContext>>()?;
 31→        let mut rx = c.subscribe();
 32→        Ok(async_stream::stream! {
 33→            while let Ok((event_name, payload)) = rx.recv().await {
 34→                if event_name == "chat" {
 35→                    if let Some(ref sk) = session_key
 36→                        && let Some(event_sk) = payload.get("sessionKey").and_then(|v| v.as_str())
 37→                        && event_sk != sk
 38→                    {
 39→                        continue;
 40→                    }
 41→                    yield GenericEvent::from(payload);
 42→                }
 43→            }
 44→        })
 45→    }
 46→
 47→    /// Session change events (patch, switch, delete).
 48→    async fn session_changed(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 49→        event_stream(ctx, "session").await
 50→    }
 51→
 52→    /// Cron job notifications (created, updated, removed, run complete).
 53→    async fn cron_notification(
 54→        &self,
 55→        ctx: &Context<'_>,
 56→    ) -> Result<impl Stream<Item = GenericEvent>> {
 57→        event_stream(ctx, "cron").await
 58→    }
 59→
 60→    /// Channel events.
 61→    async fn channel_event(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 62→        event_stream(ctx, "channel").await
 63→    }
 64→
 65→    /// Node connect/disconnect events.
 66→    async fn node_event(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 67→        event_stream(ctx, "node").await
 68→    }
 69→
 70→    /// System tick events (periodic heartbeat with stats).
 71→    async fn tick(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = TickEvent>> {
 72→        let c = ctx.data::<Arc<GqlContext>>()?;
 73→        let mut rx = c.subscribe();
 74→        Ok(async_stream::stream! {
 75→            while let Ok((name, payload)) = rx.recv().await {
 76→                if name == "tick"
 77→                    && let Ok(evt) = serde_json::from_value::<TickEvent>(payload)
 78→                {
 79→                    yield evt;
 80→                }
 81→            }
 82→        })
 83→    }
 84→
 85→    /// Log entry events.
 86→    async fn log_entry(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 87→        event_stream(ctx, "logs").await
 88→    }
 89→
 90→    /// MCP server status change events.
 91→    async fn mcp_status_changed(
 92→        &self,
 93→        ctx: &Context<'_>,
 94→    ) -> Result<impl Stream<Item = GenericEvent>> {
 95→        event_stream(ctx, "mcp.status").await
 96→    }
 97→
 98→    /// Execution approval events.
 99→    async fn approval_event(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
100→        let c = ctx.data::<Arc<GqlContext>>()?;
101→        let mut rx = c.subscribe();
102→        Ok(async_stream::stream! {
103→            while let Ok((event_name, payload)) = rx.recv().await {
104→                if event_name.starts_with("exec.approval.") {
105→                    yield GenericEvent::from(payload);
106→                }
107→            }
108→        })
109→    }
110→
111→    /// Config change events.
112→    async fn config_changed(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
113→        event_stream(ctx, "config").await
114→    }
115→
116→    /// System presence change events.
117→    async fn presence_changed(
118→        &self,
119→        ctx: &Context<'_>,
120→    ) -> Result<impl Stream<Item = GenericEvent>> {
121→        event_stream(ctx, "presence").await
122→    }
123→
124→    /// Metrics update events.
125→    async fn metrics_update(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
126→        event_stream(ctx, "metrics.update").await
127→    }
128→
129→    /// Update availability events.
130→    async fn update_available(
131→        &self,
132→        ctx: &Context<'_>,
133→    ) -> Result<impl Stream<Item = GenericEvent>> {
134→        event_stream(ctx, "update.available").await
135→    }
136→
137→    /// Voice config changed events.
138→    async fn voice_config_changed(
139→        &self,
140→        ctx: &Context<'_>,
141→    ) -> Result<impl Stream<Item = GenericEvent>> {
142→        event_stream(ctx, "voice.config.changed").await
143→    }
144→
145→    /// Skills install progress events.
146→    async fn skills_install_progress(
147→        &self,
148→        ctx: &Context<'_>,
149→    ) -> Result<impl Stream<Item = GenericEvent>> {
150→        event_stream(ctx, "skills.install.progress").await
151→    }
152→
153→    /// All events (unfiltered, for debugging).
154→    async fn all_events(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
155→        let c = ctx.data::<Arc<GqlContext>>()?;
156→        let mut rx = c.subscribe();
157→        Ok(async_stream::stream! {
158→            while let Ok((_event_name, payload)) = rx.recv().await {
159→                yield GenericEvent::from(payload);
160→            }
161→        })
162→    }
163→}
164→
165→/// Helper to create a filtered event stream for a specific event name.
166→async fn event_stream(
167→    ctx: &Context<'_>,
168→    event_name: &'static str,
169→) -> Result<impl Stream<Item = GenericEvent>> {
170→    let c = ctx.data::<Arc<GqlContext>>()?;
171→    let mut rx = c.subscribe();
172→    Ok(async_stream::stream! {
173→        while let Ok((name, payload)) = rx.recv().await {
174→            if name == event_name {
175→                yield GenericEvent::from(payload);
176→            }
177→        }
178→    })
179→}
