 59→                .as_array()
 60→                .map(|arr| {
 61→                    arr.iter()
 62→                        .filter_map(|block| {
 63→                            let block_type = block.get("type")?.as_str()?;
 64→                            match block_type {
 65→                                "text" => {
 66→                                    let text = block.get("text")?.as_str()?.to_string();
