    tx.send((
        "chat".to_string(),
        json!({ "sessionKey": "other", "text": "skip" }),
    ))
    .expect("broadcast other");
    tx.send((
        "chat".to_string(),
        json!({ "sessionKey": "s1", "text": "deliver" }),
    ))
    .expect("broadcast matching");

    let resp = timeout(Duration::from_secs(1), stream.next())
        .await
        .expect("timeout")
        .expect("subscription response");
