#[test]
fn json_wrapper_traits_and_generic_event_conversion() {
    let parsed: moltis_graphql::scalars::Json =
        serde_json::from_value(json!({"k": ["v", 2]})).expect("json deserialization");
    let cloned = parsed.clone();
    assert_eq!(cloned.0["k"][0], "v");
