        .expect("subscription response");
    assert!(all_resp.errors.is_empty(), "errors: {:?}", all_resp.errors);
    let all_json = all_resp.data.into_json().expect("json");
    assert_eq!(all_json["allEvents"]["data"]["x"], 1);
}

